import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"为你纹身","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/为你纹身.md","filePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/为你纹身.md"}'),d={name:"4.资源分区/2.改造与功法/改造/4.综合类/替身/为你纹身.md"};function p(l,a,_,i,b,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"为你纹身",tabindex:"-1"},[s("为你纹身 "),e("a",{class:"header-anchor",href:"#为你纹身","aria-label":'Permalink to "为你纹身"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新秩序006")])])],-1),o('<h1 id="为你纹身-1" tabindex="-1">为你纹身 <a class="header-anchor" href="#为你纹身-1" aria-label="Permalink to &quot;为你纹身&quot;">​</a></h1><p>为你纹身 <br> C+1200</p><p>替身外貌：<br> 替身的外形是覆盖了持有者头发和后背的报纸状纹身，于替身持有者的后脑上额外附带了一张苍白的小脸。</p><p>替身数据：<br> 破坏力 无<br> 速度E（偏斜防御）<br> 射程C<br> 持续力B<br> 精密动作性E<br> 成长性E<br> 替身对应主属性：操控</p><p>替身能力：<br> 进出纹身：觉醒为你纹身的替身使者可以将替身共享给其他人，使其他人背上也出现报纸状纹身，可共享总数为【替身使者的操控属性附加×3】人。持有纹身的人可以以同伴身上的纹身作为出入口，自由进入同伴体内的纹身空间，进出纹身空间是一个结合在移动的动作，并且不能在一个动作同时进行进出行为。每个人纹身内的容纳人数没有限制，但是所有人纹身内的总容纳体积上限为【替身使者的操控属性×50】体积。当同伴死亡时，潜伏在同伴体内的其他人不会受到影响，可以在同伴的体内缓慢地移动尸体。此外在替身使者射程范围内的纹身空间是联通的，并且可以自由决定从那个纹身出来，若替身使者处于某一个同伴体内的纹身空间时，以那个同伴为起点计算射程并共享纹身空间。<br> 以上能力是一个C级别、时空来源的异空间效果。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=r(d,[["render",p]]);export{f as __pageData,m as default};
